const GUIDE_DETAILS={
"Points percentage":{formula:"PTS ÷ (GP × 2) × 100",read:"Higher is better. 50% means one standings point earned per game.",caution:"A strong points percentage can differ from the team's underlying chance quality."},
"Goal differential":{formula:"GF − GA",read:"Positive is better; zero means goals scored and conceded are equal.",caution:"It is influenced by empty-net goals and can be noisy over short stretches."},
"Expected goals":{formula:"Sum of each shot's modelled goal probability",read:"Higher values represent a greater quantity and quality of chances.",caution:"MoneyPuck and Natural Stat Trick use different models; their xG values should not be mixed."},
"Expected goals share":{formula:"xGF ÷ (xGF + xGA) × 100",read:"Above 50% means the team owned the majority of expected-goal value.",caution:"It describes shot quality and volume, not guaranteed future scoring."},
"Goals saved above expected":{formula:"xGA − GA",read:"Positive is better; +5 means five fewer goals allowed than expected.",caution:"Results depend on the provider's expected-goals model and become more meaningful with more shots faced."},
"Corsi":{formula:"CF ÷ (CF + CA) × 100 when displayed as a share",read:"Above 50% means more total attempts for than against.",caution:"Corsi measures attempt volume, not shot quality."},
"Fenwick":{formula:"FF ÷ (FF + FA) × 100 when displayed as a share",read:"Above 50% means more unblocked attempts for than against.",caution:"It still treats every unblocked attempt equally regardless of location or type."},
"Tracker Power Index":{formula:"0.45 × (PTS% − 50) + 0.45 × (xG% − 50) + 2.5 × GD/GP",read:"Higher is better. The league is ranked from the resulting score.",caution:"This is the tracker's transparent descriptive index, not a probability or a proprietary MoneyPuck rating."},
"Tracker matchup lean":{formula:"50 + 2 × the teams' Tracker-index gap, capped between 28 and 72",read:"The larger number identifies the broader statistical edge.",caution:"The two numbers are an index presentation and must not be interpreted as win probabilities."},
"Goal Drivers":{formula:"(xGF − xGA) + (GF − xGF) + (xGA − GA) = GF − GA",read:"Expected balance, finishing and goaltending explain the displayed goal differential.",caution:"This is an accounting decomposition, not proof that one component was caused by a particular player or coach."},
"Rolling Team Balance":{formula:"Previous 10 games; xG share compared with actual goal share",read:"Similar lines suggest results and chance quality are aligned.",caution:"A ten-game window is deliberately responsive and therefore less stable than a full season."},
"Player Impact Wheel":{read:"Farther from the centre means a higher same-position percentile for that measure.",caution:"The axes are descriptive and equally displayed; the wheel is not an all-in-one value model."},
"Statistical Neighbours":{read:"A longer similarity bar means a closer same-position statistical profile.",caution:"The comparison excludes age, contract, role, linemates and most defensive context."},
"CF%":{formula:"CF ÷ (CF + CA) × 100",read:"Above 50% means more five-on-five attempts for than against.",caution:"Use the stated Natural Stat Trick situation and adjustment when comparing rows."},
"FF%":{formula:"FF ÷ (FF + FA) × 100",read:"Above 50% means more unblocked attempts for than against.",caution:"Blocked shots are excluded."},
"xGF%":{formula:"xGF ÷ (xGF + xGA) × 100",read:"Above 50% means the better expected-goal share.",caution:"Do not compare it directly with a differently defined provider model."},
"PDO":{formula:"Shooting percentage + save percentage, usually scaled around 100",read:"Above 100 means combined finishing and goaltending have run above the conventional baseline.",caution:"PDO is descriptive; moving toward 100 is a tendency, not a rule for every team."},
"Goals saved above average (GSAA)":{formula:"League-average goals allowed on the same shot count − actual goals allowed",read:"Positive is better.",caution:"Unlike GSAx, this version does not fully account for the quality of every shot faced."},
"Points (PTS)":{read:"Team PTS are standings points; player PTS are goals plus assists.",caution:"Always check whether the row refers to a team or a skater."},
"Save percentage (SV%)":{formula:"Saves ÷ shots on goal faced",read:"Higher is better; it is normally displayed to three decimal places.",caution:"It does not adjust for shot difficulty and is unstable in small samples."},
"Shooting percentage":{formula:"Goals ÷ shots on goal × 100",read:"Higher means a greater share of shots became goals.",caution:"It does not account for shot quality and can fluctuate greatly."},
"Goals-against average (GAA)":{formula:"Goals allowed × 60 ÷ goalie minutes",read:"Lower is better.",caution:"It is affected by team defence and shot volume as well as goaltending."},
"Projected season pace":{formula:"Current PTS ÷ GP × scheduled games",read:"The final total if the current points rate continued.",caution:"It is not a simulation and does not account for schedule strength or roster changes."},
"Maximum possible points":{formula:"Current PTS + 2 × games remaining",read:"The mathematical regular-season ceiling.",caution:"It assumes the team wins every remaining game."},
"Form delta":{formula:"Recent PTS% − season PTS%",read:"Positive means recent results are stronger than the full-season rate.",caution:"It compares results, not necessarily underlying performance."},
"Actual goals share":{formula:"GF ÷ (GF + GA) × 100",read:"Above 50% means more goals scored than conceded.",caution:"Finishing, goaltending and short samples can separate it from expected-goals share."},
"Goal-share gap":{formula:"Actual GF% − xGF%",read:"Positive means results are running above the expected-goal profile.",caution:"The gap identifies a difference; it does not by itself establish why it exists."},
"Points per game (P/G)":{formula:"Player PTS ÷ GP",read:"Higher means a faster scoring pace.",caution:"It does not adjust for time on ice, position or strength state."},
"Goal share (GF%)":{formula:"GF ÷ (GF + GA) × 100",read:"Above 50% is favourable.",caution:"Actual goals are less frequent and often noisier than shot-based measures."},
"Playoff path probability":{formula:"Difference between consecutive cumulative round-reach probabilities",read:"All slices sum to 100% and show the exact finishing stage.",caution:"The chart inherits the assumptions and update timing of the MoneyPuck forecast."},
"League percentile":{read:"50th is approximately league median; 90th is elite within the stated group.",caution:"Percentiles show rank, not the size of the gap between players or teams."},
"Profile similarity":{formula:"Distance across standardized selected five-on-five rates",read:"Higher similarity means the measured shapes are closer.",caution:"Similarity is not a ranking and does not mean the players have the same value."}
,"Tracker expected goals (Tracker xG)":{formula:"Logistic probability from standardized official NHL shot features",read:"A 0.18 value means the model estimates an 18% scoring chance for that attempt.",caution:"The model publishes only after minimum evidence thresholds and remains distinct from MoneyPuck and Natural Stat Trick xG."}
,"Tracker high-danger chance":{formula:"Tracker xG ≥ 0.15",read:"Each qualifying attempt had at least a 15% modelled chance of becoming a goal.",caution:"The threshold belongs only to the Tracker model; other providers use different definitions."}
};
