function visitPowerState(){const rows=DATA.standings.map(s=>{const m=mpTeam(s.team),xg=m?mpPct(m.xgPct):50,pointsPct=s.gp?s.points/(s.gp*2)*100:0,gd=s.gp?s.gd/s.gp:0;return{team:s.team,index:(pointsPct-50)*.45+(xg-50)*.45+gd*2.5,xg,pointsPct}}).sort((a,b)=>b.index-a.index);return Object.fromEntries(rows.map((row,index)=>[row.team,{rank:index+1,index:row.index,xg:row.xg,pointsPct:row.pointsPct}]))}
