function visitLeaderStates(){const followed=new Set(teams()),output={};[["points","Points"],["goals","Goals"],["gsax","GSAx"]].forEach(([metric,label])=>leaderMetricRows(metric).slice(0,50).forEach((row,index)=>{if(!followed.has(row.team))return;const key=`${metric}|${row.id||normalName(row.name)}`;output[key]={key,metric,label,rank:index+1,value:row.value,team:row.team,playerId:row.id,name:row.name}}));return output}
function visitScheduleState(){const active=DATA.scheduleRelease||{},preview=DATA.nextSeasonPreview||{},previewCount=Math.max(0,...Object.values(preview.counts||{}).map(num)),changes=Object.fromEntries((active.recentChanges||[]).map(change=>[change.key,change]));return{activeSeason:active.season||DATA.meta.season,complete:Boolean(active.complete),completedAt:active.completedAt||null,previewSeason:previewCount?preview.season:null,previewCount,previewFirstSeenAt:preview.firstSeenAt||null,changes}}
