function visitScheduleChanges(previous,current){const before=previous.schedule||{},after=current.schedule||{},changes=[],team=teams()[0];if(after.previewCount>0&&(before.previewSeason!==after.previewSeason||!before.previewCount))changes.push({type:"schedule",team,title:`${seasonLabel(after.previewSeason)} opening-night schedule detected`,detail:`${after.previewCount} announced game${after.previewCount===1?"":"s"} found for the most-covered followed team · full schedule still monitored`,page:"schedule",priority:0});if(after.complete&&after.activeSeason!==previous.season)changes.push({type:"schedule",team,title:`${seasonLabel(after.activeSeason)} full schedule verified`,detail:`All ${regularSeasonLengthFor(after.activeSeason)} games confirmed for every followed team · calendars refreshed`,page:"schedule",priority:0});else if(before.activeSeason===after.activeSeason&&before.complete===false&&after.complete)changes.push({type:"schedule",team,title:`${seasonLabel(after.activeSeason)} schedule is now complete`,detail:`Every followed team verified · permanent calendar feeds refreshed`,page:"schedule",priority:0});Object.entries(after.changes||{}).filter(([key])=>!before.changes?.[key]).slice(0,4).forEach(([,change])=>{const game=change.game||{},match=`${game.away||"TBC"} at ${game.home||"TBC"}`,kind=change.kind||"changed",detail=kind==="changed"?`Now ${game.startTimeUTC?localTime(game.startTimeUTC):scheduleDateLabel(game.date)} · calendar updated automatically`:kind==="added"?`${scheduleDateLabel(game.date)} · added to calendar feeds`:`${scheduleDateLabel(game.date)} · removed from calendar feeds`;changes.push({type:"schedule",team:[game.away,game.home].find(code=>teams().includes(code))||team,title:`${match} ${kind==="changed"?"rescheduled":kind}`,detail,page:"schedule",priority:0})});return changes}
