function playDescription(p,names,teamById){const d=p.details||{},team=teamById[d.eventOwnerTeamId]||"",player=id=>names[id]||"Unknown player",reason=String(d.descKey||d.reason||"").replaceAll("-"," ");if(p.typeDescKey==="goal")return `<strong>Goal · ${team}</strong> ${player(d.scoringPlayerId)}${d.assist1PlayerId?` from ${player(d.assist1PlayerId)}`:""}`;if(p.typeDescKey==="penalty")return `<strong>Penalty · ${team}</strong> ${player(d.committedByPlayerId)} · ${reason} (${d.duration||2} min)`;if(p.typeDescKey==="shot-on-goal")return `<strong>Shot · ${team}</strong> ${player(d.shootingPlayerId)}`;if(p.typeDescKey==="blocked-shot")return `<strong>Blocked attempt · ${team}</strong> ${player(d.shootingPlayerId)}`;if(p.typeDescKey==="missed-shot")return `<strong>Missed shot · ${team}</strong> ${player(d.shootingPlayerId)}`;if(p.typeDescKey==="hit")return `<strong>Hit · ${team}</strong> ${player(d.hittingPlayerId)} on ${player(d.hitteePlayerId)}`;return `<strong>${p.typeDescKey.replaceAll("-"," ")}</strong>`}
